gold_sparql:
PREFIX orkg: <http://orkg.org/orkg/>
PREFIX dcterms: <http://purl.org/dc/terms/>
SELECT DISTINCT ?taskType WHERE {
  ?paper a orkg:Paper ;
         orkg:hasContribution ?contribution .
  ?contribution orkg:hasDataset ?dataset ;
                orkg:hasNLPTaskType ?taskType .
  ?dataset orkg:hasDataSource ?dataSource ;
           orkg:hasLicenseType ?license .
  FILTER(REGEX(STR(?license), "open", "i"))
}
GROUP BY ?taskType ?dataset
HAVING (COUNT(DISTINCT ?dataSource) > 2)

PREFIX orkg: <http://orkg.org/orkg/>
SELECT DISTINCT ?sourceType WHERE {
  ?paper a orkg:Paper ;
         orkg:hasContribution ?contribution .
  ?contribution orkg:hasDataset ?dataset ;
                orkg:hasNLPOutputType ?outputType .
  ?dataset orkg:hasDataSourceType ?sourceType .
  FILTER(REGEX(STR(?outputType), "relation extraction", "i"))
}

PREFIX orkg: <http://orkg.org/orkg/>
SELECT DISTINCT ?naturalLanguage WHERE {
  ?paper a orkg:Paper ;
         orkg:hasContribution ?contribution .
  ?contribution orkg:hasDataset ?dataset .
  ?dataset orkg:hasNaturalLanguage ?naturalLanguage .
}

PREFIX orkg: <http://orkg.org/orkg/>
SELECT (COUNT(DISTINCT ?dataSource) AS ?numberOfDataSources) WHERE {
  ?paper a orkg:Paper ;
         orkg:hasContribution ?contribution .
  ?contribution orkg:hasDataset ?dataset ;
                orkg:hasNLPTask ?task .
  ?dataset orkg:hasDataSource ?dataSource .
  FILTER(REGEX(STR(?task), "event extraction", "i"))
}

PREFIX orkg: <http://orkg.org/orkg/>
PREFIX dcterms: <http://purl.org/dc/terms/>
SELECT DISTINCT ?publicationDate WHERE {
  ?paper a orkg:Paper ;
         dcterms:issued ?publicationDate ;
         orkg:hasContribution ?contribution .
  ?contribution orkg:hasDataset ?dataset .
  ?dataset orkg:hasLicenseType ?license ;
           orkg:hasDataSourceType ?sourceType .
  FILTER(REGEX(STR(?license), "open", "i"))
  FILTER(REGEX(STR(?sourceType), "corpus", "i"))
}
